class Solution(object):
    def minSizeSubarray(self, nums, target):
        n = len(nums)
        total = sum(nums)
        if total == 0:
            return -1
        full_cycles = target // total
        remainder = target % total
        if remainder == 0:
            return full_cycles * n
        doubled = nums + nums
        min_len = float('inf')
        window_sum = 0
        left = 0
        for right in range(2 * n):
            window_sum += doubled[right]
            while window_sum > remainder:
                window_sum -= doubled[left]
                left += 1
            if window_sum == remainder:
                min_len = min(min_len, right - left + 1)
        if min_len == float('inf'):
            return -1
        return full_cycles * n + min_len
